/**
 * IDE Command Generator - Creates IDE-specific command/skill files
 * for each selected IDE so workflows and agents appear in command palettes.
 */

const path = require('node:path');
const fs = require('fs-extra');
const yaml = require('js-yaml');

/**
 * IDE target directory mapping.
 * Maps IDE code -> relative directory where command files are written.
 */
const IDE_TARGETS = {
  'claude-code': '.claude/commands',
  cursor: '.cursor/commands',
  cline: '.clinerules/workflows',
  codex: '.codex/prompts',
  'github-copilot': '.github/prompts',
  roo: '.roo/commands',
  windsurf: '.windsurf/workflows',
};

/**
 * Generate the agent command file content.
 */
function renderAgentCommand(agentName, description, agentPath) {
  return `---
name: '${agentName}'
description: '${agentName} agent'
---

You must fully embody this agent's persona and follow all activation instructions exactly as specified. NEVER break character until given an exit command.

<agent-activation CRITICAL="TRUE">
1. LOAD the FULL agent file from {project-root}/${agentPath}
2. READ its entire contents - this contains the complete agent persona, menu, and instructions
3. FOLLOW every step in the <activation> section precisely
4. DISPLAY the welcome/greeting as instructed
5. PRESENT the numbered menu
6. WAIT for user input before proceeding
</agent-activation>
`;
}

/**
 * Generate a workflow command file content.
 */
function renderWorkflowCommand(description, workflowPath) {
  return `---
description: '${description}'
---

IT IS CRITICAL THAT YOU FOLLOW THIS COMMAND: LOAD the FULL {project-root}/${workflowPath}, READ its entire contents and follow its directions exactly!
`;
}

/**
 * Collect agent skill artifacts from the project's .claude/skills/ directory.
 * Agent skills are now standard SKILL.md-based skills (no compilation).
 * Returns array of { name, description, relativePath }.
 */
async function collectAgents(skfDir, skfFolder) {
  const agents = [];

  // Look for skf-forger (or any skf-agent-* pattern) in the installed skills
  // The agent SKILL.md is installed at .claude/skills/skf-forger/ by the installer
  const projectDir = path.resolve(skfDir, '..', '..');
  const skillsDir = path.join(projectDir, '.claude', 'skills');

  if (!(await fs.pathExists(skillsDir))) return agents;

  const entries = await fs.readdir(skillsDir, { withFileTypes: true });
  for (const entry of entries) {
    if (!entry.isDirectory() || !entry.name.startsWith('skf-')) continue;

    const skillMd = path.join(skillsDir, entry.name, 'SKILL.md');
    if (!(await fs.pathExists(skillMd))) continue;

    // Check if this is an agent skill via bmad-skill-manifest.yaml
    const manifestPath = path.join(skillsDir, entry.name, 'bmad-skill-manifest.yaml');
    if (!(await fs.pathExists(manifestPath))) continue;

    let description = `${entry.name} agent`;
    try {
      const manifest = yaml.load(await fs.readFile(manifestPath, 'utf8'));
      if (manifest && manifest.type === 'agent') {
        description = manifest.title || manifest.displayName || description;
        agents.push({
          name: manifest.displayName || entry.name,
          description,
          relativePath: `.claude/skills/${entry.name}/SKILL.md`,
        });
      }
    } catch {
      /* skip non-agent skills */
    }
  }

  return agents;
}

