      data: ['registry-resolution.md', 'skill-template.md'],
    },
    'create-stack-skill': {
      steps: [
        'step-01-init.md',
        'step-02-detect-manifests.md',
        'step-03-rank-and-confirm.md',
        'step-04-parallel-extract.md',
