        'step-04-coherence-check.md',
        'step-04b-external-validators.md',
        'step-05-score.md',
        'step-06-report.md',
      ],
      data: ['output-section-formats.md', 'scoring-rules.md', 'source-access-protocol.md'],
    },
    'verify-stack': {
      steps: [
        'step-01-init.md',
        'step-02-coverage.md',
