      data: ['refinement-rules.md'],
    },
    'export-skill': {
      steps: [
        'step-01-load-skill.md',
        'step-02-package.md',
        'step-03-generate-snippet.md',
        'step-04-update-context.md',
        'step-05-token-report.md',
        'step-06-summary.md',
      ],
      data: ['managed-section-format.md', 'snippet-format.md'],
